/*
 * Kim FS-Extra (kfs.h)
 *
 * 파일 시스템 유틸리티 라이브러리
 * - 파일/디렉토리 생성, 삭제, 복사
 * - 파일 읽기/쓰기 (편의 함수)
 * - 디렉토리 조작
 */

#ifndef KFS_H
#define KFS_H

#include <stdbool.h>

/* ============================================
   파일 정보
   ============================================ */

/**
 * 파일 존재 여부
 */
bool kfs_exists(const char *path);

/**
 * 파일 또는 디렉토리인지 확인
 */
bool kfs_is_file(const char *path);

/**
 * 디렉토리인지 확인
 */
bool kfs_is_dir(const char *path);

/**
 * 파일 크기 반환 (바이트)
 */
long kfs_size(const char *path);

/**
 * 파일 수정 시간 (Unix timestamp)
 */
long kfs_mtime(const char *path);

/* ============================================
   파일 읽기/쓰기
   ============================================ */

/**
 * 전체 파일 읽기 (메모리 할당)
 */
char* kfs_read_file(const char *path);

/**
 * 파일에 텍스트 쓰기 (덮어쓰기)
 */
bool kfs_write_file(const char *path, const char *content);

/**
 * 파일에 텍스트 추가
 */
bool kfs_append_file(const char *path, const char *content);

/**
 * JSON 파일 읽기 (간단 파싱)
 */
char* kfs_read_json(const char *path);

/**
 * JSON 파일 쓰기
 */
bool kfs_write_json(const char *path, const char *json);

/* ============================================
   파일 조작
   ============================================ */

/**
 * 파일 복사
 */
bool kfs_copy_file(const char *src, const char *dest);

/**
 * 파일 이동/이름 변경
 */
bool kfs_move_file(const char *src, const char *dest);

/**
 * 파일 삭제
 */
bool kfs_remove_file(const char *path);

/**
 * 빈 파일 생성 (touch)
 */
bool kfs_create_file(const char *path);

/* ============================================
   디렉토리 조작
   ============================================ */

/**
 * 디렉토리 생성 (존재하면 무시)
 */
bool kfs_ensure_dir(const char *path);

/**
 * 디렉토리 생성 (재귀)
 */
bool kfs_mkdir_p(const char *path);

/**
 * 디렉토리 복사 (재귀)
 */
bool kfs_copy_dir(const char *src, const char *dest);

/**
 * 디렉토리 삭제 (재귀)
 */
bool kfs_remove_dir(const char *path);

/**
 * 디렉토리 비우기 (파일만)
 */
bool kfs_empty_dir(const char *path);

/**
 * 현재 작업 디렉토리 반환
 */
char* kfs_cwd(void);

/**
 * 파일 권한 변경
 */
bool kfs_chmod(const char *path, int mode);

/**
 * 파일 상대경로 해석
 */
char* kfs_resolve(const char *path);

/* ============================================
   유틸리티
   ============================================ */

/**
 * 파일명 분리
 */
char* kfs_basename(const char *path);

/**
 * 디렉토리 경로 분리
 */
char* kfs_dirname(const char *path);

/**
 * 파일 확장자 분리
 */
char* kfs_extname(const char *path);

/**
 * 경로 조합
 */
char* kfs_join(const char *path1, const char *path2);

/**
 * 경로 정규화 (../, ./ 제거)
 */
char* kfs_normalize(const char *path);

#endif // KFS_H
